        /// <returns>Task of ResponseWorksheetToModelConversion</returns>
        System.Threading.Tasks.Task<ResponseWorksheetToModelConversion> ConvertWorksheetToModelAsync(ConvertWorksheetToModelRequest convertWorksheetToModelRequest, System.Threading.CancellationToken cancellationToken = default(global::System.Threading.CancellationToken));

